mapper.select:
SELECT ep.id, ep.period_code AS periodCode, ep.period_name AS periodName, ep.semester_id AS semesterId, s.semester_name AS semesterName, ep.academic_year AS academicYear, ep.semester_type AS semesterType, ep.data_start_date AS dataStartDate, ep.data_end_date AS dataEndDate, ep.application_start_date AS applicationStartDate, ep.application_end_date AS applicationEndDate, ep.review_start_date AS reviewStartDate, ep.review_end_date AS reviewEndDate, ep.publicity_start_date AS publicityStartDate, ep.publicity_end_date AS publicityEndDate, ep.status, ep.is_locked AS isLocked, ep.created_at AS createdAt, (SELECT COUNT(*) FROM student_evaluation_results ser WHERE ser.evaluation_period_id = ep.id) AS resultCount FROM evaluation_periods ep LEFT JOIN semesters s ON ep.semester_id = s.id WHERE ep.deleted = 0
AND ep.period_code LIKE CONCAT('%', #{query.periodCode}, '%')
AND ep.period_name LIKE CONCAT('%', #{query.periodName}, '%')
AND ep.academic_year = #{query.academicYear}
AND ep.status = #{query.status}
ORDER BY ep.academic_year DESC, ep.semester_type DESC, ep.id DESC

SELECT * FROM evaluation_periods
WHERE deleted = 0 AND academic_year = #{academicYear}
ORDER BY semester_type, id
